cases.target:
package main

import (
	"fmt"
	"os"
	"strconv"
)

func main() {
	a := func() int { v, _ := strconv.Atoi(os.Args[1]); return v }()
	b := func() int { v, _ := strconv.Atoi(os.Args[2]); return v }()
	fmt.Println(a % b)
}

